var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 하아…… 하……","JPN":" はあ……はぁ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 궁지에 몰리니 약한 척을 해서라도 살고 싶나? ","JPN":" 窮地に追い込まれた挙句、同情を誘って助かるつもりか？ ","ENG":"Does being backed into a corner make you want to live? Is that why you're acting so frail?","TWN":"竟然會被逼到絕境，是就算示弱也想活命嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 아니, 너라면 반격할 틈을 찾고 있겠군.","JPN":" いや、お前なら反撃の瞬間を見計らっているのだろうな。","ENG":"Or rather, you're probably looking for a chance to strike back.","TWN":"不對，你應該是想伺機反擊吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 미안하지만, 너에게 기회를 줄 생각은 없다.","JPN":" 悪いが、お前にそのチャンスを与えるつもりはない。","ENG":"Apologies, but I have no intention of giving you any chances.","TWN":"抱歉，我不打算給你反擊的機會。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 이만 포기해라, 네퀴티아.","JPN":" もう諦めろ、ネキティア。","ENG":"Surrender now, Nequitia.","TWN":"放棄吧，莉奎蒂亞。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 도대체 아까부터 무슨 말을 하는 거야?","JPN":" さっきから何を言ってるの？","ENG":"What in the world are you talking about?","TWN":"你到底在說什麼？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 네퀴티아라니? 내가 어딜 봐서?","JPN":" ネキティアって？　人違いじゃない？","ENG":"Nequitia? How am I Nequitia?","TWN":"什麼莉奎蒂亞？我哪裡像她？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그런 말도 안 되는 착각으로 사람을 죽이려고 들어? 당신들 제정신이야?","JPN":" そんなバカみたいな勘違いで人を殺そうとしているなんて、君たち正気？","ENG":"How can you attempt murder for such a ridiculous delusion? Are you out of your mind?","TWN":"自己認錯還想奪人家性命？你是神經病嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 착각? 그건 내가 할 소리다.","JPN":" 勘違いだと？　それはこっちのセリフだ。","ENG":"Delusion? You're the delusional one.","TWN":"我認錯？你才是有什麼誤解吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 모른 척 한다고 네가 저지른 짓이 없던 걸로 되진 않아.","JPN":" いくら白をきったところで、お前がしたことがなかったことにはならない。","ENG":"Pretending like you don't know won't erase your past actions.","TWN":"你以為裝作不知情，就可以抹滅你曾經做過的事嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그게 무슨…….","JPN":" いったい何を……","ENG":"I don't understand...","TWN":"我根本聽不懂……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 너는 네 손으로 지금 이 곳에 펼쳐진 풍경을 수도 없이 만들어 왔다.","JPN":" お前はその手で、今ここで起きているような光景を何度も作ってきた。","ENG":"You've created countless landscapes like this with your very own hands.","TWN":"你在這裡親手造成多少慘況，"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 그러니 변명할 생각은 하지 마라. 더 추해질 뿐이니까.","JPN":" だから言い訳するつもりならやめろ。余計に見苦しくなるだけだ。","ENG":"So quit with your excuses. It's revolting.","TWN":"我勸你別再狡辯，只會更難看而已。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 큭…….","JPN":" くっ……","ENG":"Kgh...","TWN":"唔……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 에클레시아!","JPN":" エクレシア！","ENG":"Ecclesia!","TWN":"艾可露西亞！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" ……음?","JPN":" ……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 하필이면 가장 엮이면 안 될 상대와 마주쳤구나. 레아 슈나이더.","JPN":" 運悪く最も関わってはいけない相手と遭遇してしまったな。レア・シュナイダー。","ENG":"A most unfortunate encounter for you, Leah Schneider.","TWN":"你偏偏遇到最難纏的對手，蕾亞·修奈德。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 혹시나 해서 불렀는데…… 정말 와 줬네요.","JPN":" 一か八かが呼んでみましたが……本当に来てくれたんですね。","ENG":"I wasn't sure, but... you really came.","TWN":"我只是喊喊看而已……你還真的出現啦？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 믿음을 요구하면 그에 부응하는 것이 마땅한 의무일지니.","JPN":" 信用してもらったからには、それに答えるのは義務だろう。","ENG":"It is my rightful duty to respond, as I have requested faith from you.","TWN":"若要取得他人的信任，說到做到是應盡的義務。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 지체 말고 가거라, 레아 슈나이더. 사방이 고요해질 때까지.","JPN":" 振り返らずに進め、レア・シュナイダー。辺りが完全に静まるまで。","ENG":"Tread on without hesitation, Leah Schneider. Until your surroundings become silent.","TWN":"不要耽誤，跑，跑到四周安靜下來為止。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 알겠어요. 이런 난리통에 얼마나 도망칠 수 있을지 모르겠지만.","JPN":" わかりました。こんなめちゃくちゃな現場から逃げられるかはわかりませんけど。","ENG":"Okay. I'm not sure how far I can go with all this chaos around me, though.","TWN":"好，只是我不知道在這種情況下我能跑多遠。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 너는……. 설마 <color=#ffd34c>원본</color>인가? ","JPN":" お前はまさか……<color=#ffd34c>オリジナル</color>なのか？ ","ENG":"You... Are you the <color=#ffd34c>original</color>?","TWN":"你……難道是<color=#ffd34c>本體</color>？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 다른 사람도 아닌 네가 왜 저 괴물을 감싸고 도는 거지?","JPN":" 他でもない、お前があの化け物を庇うのはなぜだ？","ENG":"How are you the one who's protecting that monster?","TWN":"你為什麼要包庇那個怪物？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 핍박이 너의 역할이듯, 길을 인도하는 것이 내게 주어진 역할이기 때문이다.","JPN":" 迫害がそなたの役割であるように、道しるべとなるのが我に与えられた役割だ。","ENG":"It is because guiding one's path is the role I was given, as persecution is yours.","TWN":"因為你的角色是逼迫人，而我的角色則是替人引路。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 그러니 검을 들어라. 발키리가 남긴 잔영이여. ","JPN":" ゆえに剣を取れ、ヴァルキリーが残した残影よ。 ","ENG":"So, raise your sword, trace of the Valkyrie.","TWN":"所以把劍收起來吧，女武神的殘影。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" ……뚫린 입이라고 함부로 말하는군.","JPN":" ……舐めた口を利きやがって。","ENG":"...Nobody taught you how to shut up, huh?","TWN":"……輪得到你在這邊說三道四嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 나유빈, 이수연. 물러서라.","JPN":" イチノセ、カナミ。下がっていろ。","ENG":"Yubin, Sooyeon. Stand back.","TWN":"羅瑜斌、李秀妍，你們退下。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":" 스승님?","JPN":" 師匠？","ENG":"Master?","TWN":"師父？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":" 무슨 말씀이세요! 스승님과 제 힘을 합치면 저런 이상한 녀석 따위 한 방이라구요!","JPN":" 何を言っているんですか！　師匠と私が力を合わせればあんなおかしな奴なんてイチコロですから！","ENG":"What do you mean?! As long as we work together that creepy monster won't stand a chance!","TWN":"為什麼！師父和我加起來，一拳就能打敗那傢伙吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 그만둬라. 지금 네 실력으로는 감당 못해.","JPN":" やめておけ。お前の力じゃ敵わないぞ。","ENG":"Stop. You won't be able to handle her power.","TWN":"別說了，以你現在的能力是無法承受的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":" 네?","JPN":" え？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 그거 아나? 내 눈에는 침식체들보다 네가 더 괴물로 보인다는 걸.","JPN":" いいか？　私の目には侵食体よりお前の方がよっぽど化け物に見える。","ENG":"Did you know? To me, you look more like a monster than C.O.s.","TWN":"你知道嗎？在我看來，你比那些侵蝕體更像怪物。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 그러니 어디 막아서 봐라. 괴물.","JPN":" だから私を止めてみろ。化け物。","ENG":"So, try and stop me. Monster.","TWN":"有本事就盡管攔我吧，怪物。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":" 사람들의 비명과 절규가 계속해서 울려 퍼진다.","JPN":" 人々の悲鳴と絶叫があちこちから止むことなく聞こえてくる。","ENG":"The sound of people screaming and crying kept ringing in my ears.","TWN":"人們的哀號和慘叫聲不絕於耳。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":" 도망쳐도, 도망쳐도 귓가에서 떨어지지 않아서.","JPN":" 逃げても逃げても、耳から離れない。","ENG":"I ran, and I ran, but it didn't stop.","TWN":"無論我怎麼逃，始終都聽得到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":" 결국에는 그저 조용해지기만을 기도했다.","JPN":" 最後にはただただこの声が収まることを祈った。","ENG":"In the end, I just prayed for it to go silent.","TWN":"最後我只能祈禱能夠安靜下來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 여기는……","JPN":" ここは……","ENG":"This place is...","TWN":"這裡是……"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 벗어난 거야? 그 지옥에서?","JPN":" 外に出られた？　あの地獄から？","ENG":"Did I get out? From that hellhole?","TWN":"我從那個地獄逃出來了嗎？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":" 아니. 네가 방금 전 헤매던 곳도 이 객차의 일부다.","JPN":" いや。そなたが先程彷徨っていた場所もこの客車の一部だ。","ENG":"You did not. The area you were lost in is also a part of this train.","TWN":"不，你剛才所在的地方也是車廂的一部分。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 이런……!","JPN":" しまった……！","ENG":"What...?!","TWN":"可惡……！"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 무기를 거두어라, 레아 슈나이더.","JPN":" 武器をしまえ、レア・シュナイダー。","ENG":"Sheathe your weapon, Leah Schneider.","TWN":"把武器收起來，蕾亞·修奈德。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 에클레시아? 방금 그 사람들은 그럼 어떻게 된 거죠?","JPN":" エクレシア？　じゃあさっきの人たちはどうなったんですか？","ENG":"Ecclesia? What happened to those people?","TWN":"艾可露西亞？剛才那些人呢？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 늑대의 문양을 지닌 자들이라면 안심하라. 그들은 너를 핍박하길 단념하였으니.","JPN":" 狼の紋章が入っている者たちのことなら安心しろ。彼らはそなたを迫害することを諦めた。","ENG":"You may lower your guard around those who bear the Seal of the Wolf, as they have relinquished the thought of persecuting you.","TWN":"無需擔心那些有狼紋的人，他們已經放棄逼迫你。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 에클레시아, 미안하지만 제 질문에 답을 해 줘야겠어요.","JPN":" エクレシア、悪いけど、私の質問に答えてくれますか。","ENG":"I'm sorry, but I'm afraid you're going to have to answer my question, Ecclesia.","TWN":"艾可露西亞，你可以回答我一個問題嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 질문? 무엇인가?","JPN":" 質問？　なんの質問だ？","ENG":"Question? Which is?","TWN":"什麼問題？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 저는 지금 이 상황과 비슷한 경험을 한 적이 있어요.","JPN":" 私は今と同じような状況を経験したことがあります。","ENG":"I've been in a similar situation to this one.","TWN":"我曾經有過跟現在類似的經驗。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 혹시 이 열차는, 제 머릿속에 존재하는 공간인가요?","JPN":" もしかしてこの列車は、私の頭の中だけに存在している空間なんですか？","ENG":"Is this train a space that exists in my head?","TWN":"這台列車是存在於我腦海裡的空間嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 어찌하여 그런 결론에 다다르게 되었나?","JPN":" どうしてそのように考えた？","ENG":"How have you come to that conclusion?","TWN":"你是如何得出這個結論的？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 방금 겪은 상황이 워낙에 노골적이었으니까요.","JPN":" さっきの状況があまりにも露骨だったからです。","ENG":"It was pretty obvious, based on what just happened.","TWN":"因為剛才的情況非常明顯。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 직업상 한 번 본 얼굴은 잊지 않는 편인데, 그 사람들은 전부 오늘 처음 마주쳤어요.","JPN":" 職業柄、一度見た顔は忘れないのですが、あの人たちは皆、今日初めて見る人たちでした。","ENG":"I'm good with faces due to my job. But I've never met those people before.","TWN":"在工作中遇見的人我幾乎是過目不忘，但剛才那些人我全都是第一次見到。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그런데 다들 저를 네퀴티아로 여기고 죽이려 들었잖아요?","JPN":" でもみんな、私をネキティアだと認識して襲い掛かってきましたよね？","ENG":"But they called me Nequitia and tried to kill me.","TWN":"而且他們不僅把我誤認為是一個叫莉奎蒂亞的人，甚至還想殺我。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 설득은커녕, 애초에 서로 다른 시간대를 인지하면서 행동하는 느낌이었어요.","JPN":" 説得はおろか、そもそもお互いが別々の時間軸を見ているかのような感じでした。","ENG":"I couldn't get through to them, rather, it felt like we were in different time periods.","TWN":"好像怎麼解釋都沒用，感覺似乎打從一開始我們就在不同的時空中。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 네퀴티아의 의식이 되살아날 때 겪었던 것처럼요.","JPN":" ネキティアの意識が蘇ってきた時のようにです。","ENG":"Similar to when Nequitia's consciousness came to.","TWN":"感覺很像之前莉奎蒂亞的意識恢復時發生的情形。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 그렇군. 네가 내린 결론은 틀리지 않았다.","JPN":" そうか。ならばそなたの出した結論は正しい。","ENG":"I see. Your conclusion is correct.","TWN":"原來如此，你的結論沒錯。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 바로 알아채다니 과연 영민하군. 예지의 성흔을 받은 이들이나 익숙한 감각이거늘","JPN":" すぐにそのことに気付くとは、さすがだ。そのような感覚を持つのは予知の聖痕を授かった者ぐらいであろうに。","ENG":"You are clever to have noticed it immediately. It is a sense only familiar to those who were graced with the Stigmata of foresight.","TWN":"竟然能夠這麼快就發現，果然很敏銳。甚至能夠媲美那些有得到預知聖痕的人。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 하지만 그렇다면 걸리는 점이 하나 더 있네요.","JPN":" だとしたらもう一つ気になる点があります。","ENG":"But then, there's one more thing that's confusing.","TWN":"但我還有一個疑問。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 여기가 <color=#ffd34c>네퀴티아</color>의 머릿속이라는 건 이해했어요.","JPN":" ここが<color=#ffd34c>ネキティア</color>の意識の中なのは理解しました。","ENG":"I understand this is the inside of <color=#ffd34c>Nequitia's</color> mind.","TWN":"我知道這裡是<color=#ffd34c>莉奎蒂亞</color>的腦海裡的空間。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 그럼 여기 있는 저는 대체 뭐죠?","JPN":" ならば、ここにいる私はいったい何なんですか？","ENG":"Then, what am I?","TWN":"那在這裡的我到底是什麼？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 우리는…… 이렇게 말하면 조금 이상하게 들릴 수 있다는 건 알지만, 서로가 합의에 도달했다고 생각했거든요.","JPN":" 私たちは……こう言うと少し変に聞こえるかもしれませんが、お互いが合意できたのだと思っていました。","ENG":"I.. Well, this might sound a little weird, but I thought we came to an agreement.","TWN":"我們……這麼說好像有點奇怪，但我以為我們有達成協議。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 네퀴티아의 의식이 부상하기 시작한 순간부터 멈추기는 불가능했고.","JPN":" ネキティアの意識が浮上しはじめた瞬間から、止めるのは無理で。","ENG":"It wasn't possible to stop Nequitia as her consciousness started to emerge.","TWN":"莉奎蒂亞的意識一旦浮上來，就不會停止。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 저 자신이 레아 슈나이더의 기억으로 살았던 네퀴티아라는 걸 자각해 버렸으니까요.","JPN":" 私は自分自身がレア・シュナイダーの記憶を持って生きてきたネキティアだということに気づいてしまったから。","ENG":"And I realized I was just Nequitia who lived with Leah Schneider's memories.","TWN":"現在的我也許只是以蕾亞·修奈德記憶活著的莉奎蒂亞。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 레아 슈나이더라는 인간은 사라졌다고 생각했는데…….","JPN":" それでレア・シュナイダーという人間は消えたと思っていたのに……","ENG":"I thought the human Leah Schneider disappeared...","TWN":"而蕾亞·修奈德這個人已經從世界上消失……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 인간성.","JPN":" 人間性。","ENG":"Humanity.","TWN":"人性。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":" 네?","JPN":" え？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 너는 너 자신이 누군지 잊고 인간으로 지내는 동안 싹튼.","JPN":" そなたは自身が何者であるかを忘却し、人間として生きていた間に芽生えた……","ENG":"You are what developed while you were guised as a human without memory of your true identity.","TWN":"在你忘記自己是誰，以人類之姿萌發出的人性。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":" 마지막 인간성이다.","JPN":" 最後の人間性だ。","ENG":"The last humanity remaining.","TWN":"你就是那最後的人性。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};